+            threshold: 50,
+            blocked_actions: vec!["a".into(), "b".into()],
+        };
+        let mut cloned = original.clone();
+        if let GuardrailEvent::Triggered {
+            ref mut blocked_actions,
+            ..
+        } = cloned
+        {
+            blocked_actions.push("c".into());
+        }
+        // Original unchanged
+        if let GuardrailEvent::Triggered {
+            blocked_actions, ..
+        } = &original
+        {
+            assert_eq!(blocked_actions.len(), 2);
+        } else {
+            panic!("wrong variant");
